    const n = nums.length;

    // 1. Find the peak index
    let peakIndex = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1] && nums[i] > nums[i + 1]) {
            peakIndex = i;
            break;
        }
        // Handle the case where the peak is the last element (strictly increasing)
        // Although the problem implies a peak where it starts decreasing,
        // for a strictly increasing array, the last element is the peak.
        // For a strictly decreasing array, the first element is the peak.
        if (i === n - 1 && nums[i] > nums[i - 1]) {
            peakIndex = i;
            break;
        }
