    // Handle edge case where the array is strictly increasing (peak is at n-1)
    // If the loop finishes without finding a clear peak (like [1, 2, 3]), 
    // the peak is the last element.
    if (peakIndex === 0) {
        // Check if it's strictly increasing (e.g., [1, 2, 3])
        let isStrictlyIncreasing = true;
        for (let i = 1; i < n; i++) {
            if (nums[i] < nums[i - 1]) {
                isStrictlyIncreasing = false;
                break;
            }
        }
        if (isStrictlyIncreasing) {
            peakIndex = n - 1;
        } else {
            // Check if it's strictly decreasing (e.g., [3, 2, 1])
            let isStrictlyDecreasing = true;
            for (let i = 1; i < n; i++) {
                if (nums[i] > nums[i - 1]) {
                    isStrictlyDecreasing = false;
                    break;
                }
            }
            if (isStrictlyDecreasing) {
                peakIndex = 0;
            }
        }
    }


    // 2. Calculate the sum of the increasing part (0 to peakIndex)
    let sumIncreasing = 0;
    for (let i = 0; i <= peakIndex; i++) {
        sumIncreasing += nums[i];
    }

    // 3. Calculate the sum of the decreasing part (peakIndex to n-1)
    let sumDecreasing = 0;
    for (let i = peakIndex; i < n; i++) {
        sumDecreasing += nums[i];
    }

    // 4. Compare and return the result
    if (sumIncreasing > sumDecreasing) {
        return 0;
    } else if (sumDecreasing > sumIncreasing) {
        return 1;
    } else {
        return -1;
    }
}

